mapper.select:
SELECT e.ROUTE_EDGE_ID, e.PLANT_CD, e.EDGE_CD, e.EDGE_NM, e.FROM_NODE_ID, e.TO_NODE_ID, e.BIDIRECTIONAL_YN, e.DISTANCE_M, e.TRAVEL_TIME_SEC, e.BASE_COST, e.EDGE_STATUS, e.USE_YN, e.REG_USER_ID, e.REG_DTM, e.UPD_USER_ID, e.UPD_DTM, fn.NODE_CD AS FROM_NODE_CD, fn.NODE_NM AS FROM_NODE_NM, tn.NODE_CD AS TO_NODE_CD, tn.NODE_NM AS TO_NODE_NM, c.COM_NM AS EDGE_STATUS_NM FROM MCS_ROUTE_EDGE e INNER JOIN MCS_ROUTE_NODE fn ON e.FROM_NODE_ID = fn.ROUTE_NODE_ID INNER JOIN MCS_ROUTE_NODE tn ON e.TO_NODE_ID = tn.ROUTE_NODE_ID LEFT JOIN COM_CODE c ON c.GRP_CD = 'MCS_EDGE_STATUS' AND e.EDGE_STATUS = c.COM_CD
AND e.PLANT_CD = #{plantCd} AND e.EDGE_CD LIKE CONCAT('%', #{edgeCd}, '%') AND e.EDGE_STATUS = #{edgeStatus}
ORDER BY e.PLANT_CD, e.EDGE_CD
